content.css:
.journey-sankey {
  width: 100%;
  height: 100%;
  overflow: hidden;
}
.sankey-tooltip {
  position: absolute;
  pointer-events: none;
  background: rgba(0, 0, 0, 0.85);
  color: #fff;
  border-radius: 6px;
  padding: 8px 12px;
  font-size: 12px;
  line-height: 1.5;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25);
  z-index: 9999;
  max-width: 300px;
  transition: opacity 0.15s ease;
}
.node rect {
  cursor: pointer;
  transition: stroke 0.15s ease, stroke-width 0.15s ease;
}
.node rect:hover {
  filter: brightness(0.9);
}
.links path {
  cursor: pointer;
  transition: stroke-opacity 0.15s ease;
}
.level-headers text {
  user-select: none;
  font-family: "Segoe UI", wf_segoe-ui_normal, helvetica, arial, sans-serif;
}
.node text {
  user-select: none;
  font-family: "Segoe UI", wf_segoe-ui_normal, helvetica, arial, sans-serif;
  pointer-events: none;
}
